solution_code:
#include <iostream>
#include <string>
#include <string_view>

enum Day { monday = 0, tuesday, wednesday, thursday, friday, saturday, sunday };

constexpr std::string_view dayToString(Day d) {
    switch (d) {
        case monday:    return "monday";
        case tuesday:   return "tuesday";
        case wednesday: return "wednesday";
        case thursday:  return "thursday";
        case friday:    return "friday";
        case saturday:  return "saturday";
        case sunday:    return "sunday";
        default:        return "invalid";
    }
}

int stringToDay(std::string_view s) {
    if (s == "monday")         return monday;
    else if (s == "tuesday")   return tuesday;
    else if (s == "wednesday") return wednesday;
    else if (s == "thursday")  return thursday;
    else if (s == "friday")    return friday;
    else if (s == "saturday")  return saturday;
    else if (s == "sunday")    return sunday;
    else return -1;
}

int main() {
    int n{};
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        std::string input;
        std::cin >> input;
        int val = stringToDay(input);
        if (val == -1) {
            std::cout << "invalid = -1\n";
        } else {
            Day d = static_cast<Day>(val);
            std::cout << dayToString(d) << " = " << val << '\n';
        }
    }
    return 0;
}
